/// Possible value suggestions for a property.
#[derive(Debug, Clone)]
pub enum ValueSuggestion {
    /// A value from a schema `enum` array.
    Enum(serde_json::Value),
    /// A value from a schema `const`.
    Const(serde_json::Value),
    /// Suggests `true` and `false`.
    Boolean,
    /// Suggests `null`.
    Null,
}

/// Key used to deduplicate value suggestions.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
enum ValueSuggestionKey {
    Boolean,
    Null,
    Enum(String),
    Const(String),
}

fn value_suggestion_key(suggestion: &ValueSuggestion) -> ValueSuggestionKey {
    match suggestion {
        ValueSuggestion::Enum(v) => ValueSuggestionKey::Enum(serde_json::to_string(v).unwrap()),
        ValueSuggestion::Const(v) => ValueSuggestionKey::Const(serde_json::to_string(v).unwrap()),
        ValueSuggestion::Boolean => ValueSuggestionKey::Boolean,
        ValueSuggestion::Null => ValueSuggestionKey::Null,
    }
}

