/// Collect possible value suggestions for a property at the given pointer path.
///
/// Navigates to the subschema at `pointer` + `property_name`, then inspects
/// `enum`, `const`, `type`, and composition keywords to generate value
/// suggestions. Results are deduplicated so overlapping branches do not
/// produce duplicate completion items.
pub fn collect_values(
    root: &serde_json::Value,
    pointer: &[String],
    property_name: &str,
) -> Vec<ValueSuggestion> {
    let mut full_pointer: Vec<String> = pointer.to_vec();
    full_pointer.push(property_name.to_string());

    let Some(subschema) = resolve_subschema_at_pointer(root, &full_pointer) else {
        return vec![];
    };

    let mut suggestions = Vec::new();
    let mut seen = HashSet::new();
    collect_values_from(root, subschema, &mut suggestions, &mut seen, 0);
    suggestions
}

/// Recursively collect value suggestions from a schema and its composition
/// branches, deduplicating by value.
fn collect_values_from(
    root: &serde_json::Value,
    schema: &serde_json::Value,
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<ValueSuggestionKey>,
    depth: usize,
) {
    if depth > MAX_SCHEMA_DEPTH {
        return;
    }

    // Follow $ref.
    let mut visited = HashSet::new();
    let Some(schema) = follow_ref(root, schema, &mut visited) else {
        return;
    };

    // Check for const (a single fixed value).
    if let Some(const_val) = schema.get("const") {
        let suggestion = ValueSuggestion::Const(const_val.clone());
        if seen.insert(value_suggestion_key(&suggestion)) {
            suggestions.push(suggestion);
        }
        return;
    }

    // Check for enum (a list of allowed values).
    if let Some(enum_vals) = schema.get("enum").and_then(|v| v.as_array()) {
        for val in enum_vals {
            let suggestion = ValueSuggestion::Enum(val.clone());
            if seen.insert(value_suggestion_key(&suggestion)) {
                suggestions.push(suggestion);
            }
        }
        return;
    }

    // Check for type-based suggestions.
    if let Some(type_value) = schema.get("type") {
        collect_type_value_suggestions(type_value, suggestions, seen);
    }

    // OpenAPI-style `nullable: true` adds null as a valid value.
    if schema.get("nullable").and_then(|v| v.as_bool()) == Some(true) {
        let suggestion = ValueSuggestion::Null;
        if seen.insert(value_suggestion_key(&suggestion)) {
            suggestions.push(suggestion);
        }
    }

    // Recurse into composition branches.
    for key in ["allOf", "anyOf", "oneOf"] {
        if let Some(branches) = schema.get(key).and_then(|v| v.as_array()) {
            for branch in branches {
                collect_values_from(root, branch, suggestions, seen, depth + 1);
            }
        }
    }

    // Conditional subschemas.
    if let Some(then) = schema.get("then") {
        collect_values_from(root, then, suggestions, seen, depth + 1);
    }
    if let Some(else_) = schema.get("else") {
        collect_values_from(root, else_, suggestions, seen, depth + 1);
    }
}

/// Convert a JSON Schema `type` value into value suggestions.
fn collect_type_value_suggestions(
    type_value: &serde_json::Value,
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<ValueSuggestionKey>,
) {
    let add = |suggestions: &mut Vec<ValueSuggestion>,
               seen: &mut HashSet<ValueSuggestionKey>,
               suggestion: ValueSuggestion| {
        if seen.insert(value_suggestion_key(&suggestion)) {
            suggestions.push(suggestion);
        }
    };

    match type_value {
        serde_json::Value::String(s) => match s.as_str() {
            "boolean" => add(suggestions, seen, ValueSuggestion::Boolean),
            "null" => add(suggestions, seen, ValueSuggestion::Null),
            _ => {}
        },
        serde_json::Value::Array(arr) => {
            for t in arr {
                if let Some(s) = t.as_str() {
                    match s {
                        "boolean" => add(suggestions, seen, ValueSuggestion::Boolean),
                        "null" => add(suggestions, seen, ValueSuggestion::Null),
                        _ => {}
                    }
                }
            }
        }
        _ => {}
    }
}

