    #[test]
    fn hover_truncate_multibyte_boundary() {
        // Place a 4-byte emoji (U+1F600) right at the 10,000-byte boundary.
        let prefix = "x".repeat(9_999);
        let long_desc = format!("{prefix}\u{1F600}extra");

        let schema = serde_json::json!({
            "properties": {
                "x": { "description": long_desc }
            }
        });

        // Must not panic, and must produce valid truncated output.
        let result = lookup_hover_content(&schema, &["x".into()]).unwrap();
        assert!(result.ends_with("..."));
        // The emoji straddles byte 10,000, so it should be excluded.
        assert!(!result.contains('\u{1F600}'));
    }
}

input.newString:
    #[test]
    fn hover_truncate_multibyte_boundary() {
        // Place a 4-byte emoji (U+1F600) right at the 10,000-byte boundary.
        let prefix = "x".repeat(9_999);
        let long_desc = format!("{prefix}\u{1F600}extra");

        let schema = serde_json::json!({
            "properties": {
                "x": { "description": long_desc }
            }
        });

        // Must not panic, and must produce valid truncated output.
        let result = lookup_hover_content(&schema, &["x".into()]).unwrap();
        assert!(result.ends_with("..."));
        // The emoji straddles byte 10,000, so it should be excluded.
        assert!(!result.contains('\u{1F600}'));
    }

    #[test]
    fn collect_properties_anyof_union() {
        let schema = serde_json::json!({
            "anyOf": [
                { "properties": { "name": { "type": "string" } }, "required": ["name"] },
                { "properties": { "age": { "type": "number" } } }
            ]
        });
        let props = collect_properties(&schema, &[]);
        let names: Vec<String> = props.iter().map(|p| p.name.clone()).collect();
        assert_eq!(names.len(), 2);
        assert!(names.contains(&"name".to_string()));
        assert!(names.contains(&"age".to_string()));
        // Required from anyOf branches should not be inherited.
        let name_prop = props.iter().find(|p| p.name == "name").unwrap();
        assert!(!name_prop.required);
    }

    #[test]
    fn collect_properties_oneof_union() {
        let schema = serde_json::json!({
            "oneOf": [
                { "properties": { "dark": { "type": "boolean" } } },
                { "properties": { "light": { "type": "boolean" } } }
            ]
        });
        let props = collect_properties(&schema, &[]);
        let names: Vec<String> = props.iter().map(|p| p.name.clone()).collect();
        assert_eq!(names.len(), 2);
        assert!(names.contains(&"dark".to_string()));
        assert!(names.contains(&"light".to_string()));
    }

    #[test]
    fn collect_properties_allof_no_duplicates() {
        let schema = serde_json::json!({
            "allOf": [
                { "properties": { "name": { "type": "string" } }, "required": ["name"] },
                { "properties": { "name": { "type": "string" }, "age": { "type": "number" } } }
            ]
        });
        let props = collect_properties(&schema, &[]);
        assert_eq!(props.len(), 2);
        let name_prop = props.iter().find(|p| p.name == "name").unwrap();
        assert!(name_prop.required);
    }

    #[test]
    fn collect_values_nullable_array_type() {
        let schema = serde_json::json!({
            "properties": {
                "nickname": { "type": ["string", "null"] }
            }
        });
        let values = collect_values(&schema, &[], "nickname");
        assert_eq!(values.len(), 1);
        assert!(matches!(&values[0], ValueSuggestion::Null));
    }

    #[test]
    fn collect_values_nullable_openapi() {
        let schema = serde_json::json!({
            "properties": {
                "count": { "type": "integer", "nullable": true }
            }
        });
        let values = collect_values(&schema, &[], "count");
        assert_eq!(values.len(), 1);
        assert!(matches!(&values[0], ValueSuggestion::Null));
    }

    #[test]
    fn collect_values_anyof_with_null() {
        let schema = serde_json::json!({
            "properties": {
                "enabled": {
                    "anyOf": [
                        { "type": "boolean" },
                        { "type": "null" }
                    ]
                }
            }
        });
        let values = collect_values(&schema, &[], "enabled");
        assert_eq!(values.len(), 2);
        assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Boolean)));
        assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Null)));
    }

    #[test]
    fn collect_values_anyof_enum_and_boolean() {
        let schema = serde_json::json!({
            "properties": {
                "mode": {
                    "anyOf": [
                        { "enum": ["dark", "light"] },
                        { "type": "boolean" }
                    ]
                }
            }
        });
        let values = collect_values(&schema, &[], "mode");
        assert_eq!(values.len(), 4);
        assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Enum(v) if v == "dark")));
        assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Enum(v) if v == "light")));
        assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Boolean)));
    }

    #[test]
    fn collect_values_no_duplicates_across_branches() {
        let schema = serde_json::json!({
            "properties": {
                "mode": {
                    "anyOf": [
                        { "enum": ["dark", "light"] },
                        { "enum": ["light", "auto"] }
                    ]
                }
            }
        });
        let values = collect_values(&schema, &[], "mode");
        assert_eq!(values.len(), 3);
        let labels: Vec<String> = values
            .iter()
            .map(|v| match v {
                ValueSuggestion::Enum(v) => v.as_str().unwrap().to_string(),
                _ => panic!("unexpected suggestion"),
            })
            .collect();
        assert!(labels.contains(&"dark".to_string()));
        assert!(labels.contains(&"light".to_string()));
        assert!(labels.contains(&"auto".to_string()));
    }
}

