// --- Composed schema completion tests ---

/// Absolute path to the composed-schema completion test schema.
fn composed_schema_path() -> String {
    format!(
        "{}/tests/fixtures/completion-composed-schema.json",
        env!("CARGO_MANIFEST_DIR")
    )
}

/// A test document URI for the composed schema.
fn composed_doc_uri() -> String {
    file_uri(&format!(
        "{}/tests/fixtures/test-completion-composed-doc.json",
        env!("CARGO_MANIFEST_DIR")
    ))
}

/// Build a JSON document with an absolute $schema pointing to the composed schema.
fn doc_with_composed_schema(content: &str) -> String {
    let schema = composed_schema_path();
    if content.is_empty() {
        format!(r#"{{"$schema": "{schema}"}}"#)
    } else {
        format!(r#"{{"$schema": "{schema}", {content}}}"#)
    }
}

/// Property completions are collected from all allOf branches.
#[tokio::test]
async fn completion_allof_merges_properties() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_composed_schema("");
    let uri = composed_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let cursor_col = (content.len() - 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let names = labels(&result);
    assert!(
        names.contains(&"id".to_string()),
        "expected 'id' from allOf Base, got: {names:?}"
    );
    assert!(
        names.contains(&"count".to_string()),
        "expected 'count' from allOf Extended, got: {names:?}"
    );
}

/// Properties that appear in multiple allOf branches are suggested only once.
#[tokio::test]
async fn completion_allof_deduplicates_properties() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_composed_schema("");
    let uri = composed_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let cursor_col = (content.len() - 1) as u32;
    let result = client.completion(&uri, 0, cursor_col).await;

    let name_count = labels(&result)
        .iter()
        .filter(|n| *n == "name")
        .count();
    assert_eq!(
        name_count, 1,
        "'name' should appear exactly once in allOf completions"
    );
}

/// Property completions include alternatives from anyOf branches.
#[tokio::test]
async fn completion_anyof_includes_alternative_properties() {
    let mut client = TestClient::new();
