/// Value completion for a property with anyOf boolean/null.
#[tokio::test]
async fn completion_anyof_boolean_null_values() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_composed_schema(r#""optionalBool": null"#);
    let uri = composed_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let idx = content.find("\"optionalBool\": ").unwrap() + "\"optionalBool\": ".len();
    let result = client.completion(&uri, 0, idx as u32).await;

    let names = labels(&result);
    assert!(
        names.contains(&"true".to_string()),
        "expected 'true' for boolean branch, got: {names:?}"
    );
    assert!(
        names.contains(&"false".to_string()),
        "expected 'false' for boolean branch, got: {names:?}"
    );
    assert!(
        names.contains(&"null".to_string()),
        "expected 'null' for null branch, got: {names:?}"
    );
}

/// Value completion for a property with anyOf enum and boolean branches.
#[tokio::test]
async fn completion_anyof_enum_and_boolean_values() {
    let mut client = TestClient::new();
    client.initialize().await;

    let content = doc_with_composed_schema(r#""mixedMode": null"#);
    let uri = composed_doc_uri();
    open_and_wait(&mut client, &uri, &content).await;

    let idx = content.find("\"mixedMode\": ").unwrap() + "\"mixedMode\": ".len();
    let result = client.completion(&uri, 0, idx as u32).await;

    let names = labels(&result);
    assert!(
        names.contains(&r#""dark""#.to_string()),
        "expected '\"dark\"' from enum branch, got: {names:?}"
    );
    assert!(
        names.contains(&r#""light""#.to_string()),
        "expected '\"light\"' from enum branch, got: {names:?}"
    );
    assert!(
        names.contains(&"true".to_string()),
        "expected 'true' from boolean branch, got: {names:?}"
    );
    assert!(
        names.contains(&"false".to_string()),
        "expected 'false' from boolean branch, got: {names:?}"
    );
}

