display.text:
const MAX_SCHEMA_DEPTH: usize = 32;

/// Information about a completable property from a schema.
#[derive(Debug, Clone)]
pub struct PropertyInfo {
    pub name: String,
    pub required: bool,
    pub description: Option<String>,
    pub schema_type: Option<String>,
}

/// Possible value suggestions for a property.
#[derive(Debug, Clone)]
pub enum ValueSuggestion {
    /// A value from a schema `enum` array.
    Enum(serde_json::Value),
    /// A value from a schema `const`.
    Const(serde_json::Value),
    /// Suggests `true` and `false`.
    Boolean,
    /// Suggests `null`.
    Null,
}

/// Key used to deduplicate value suggestions.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
enum ValueSuggestionKey {
    Boolean,
    Null,
    Enum(String),
    Const(String),
}

fn value_suggestion_key(suggestion: &ValueSuggestion) -> ValueSuggestionKey {
    match suggestion {
        ValueSuggestion::Enum(v) => ValueSuggestionKey::Enum(serde_json::to_string(v).unwrap()),
        ValueSuggestion::Const(v) => ValueSuggestionKey::Const(serde_json::to_string(v).unwrap()),
        ValueSuggestion::Boolean => ValueSuggestionKey::Boolean,
        ValueSuggestion::Null => ValueSuggestionKey::Null,
    }
}

/// Collect all completable properties from a schema at the given pointer path.
///
/// Follows `$ref` and merges `allOf` branches. Returns an empty vec if the
/// resolved subschema is not an object schema or the pointer cannot be resolved.
pub fn collect_properties(root: &serde_json::Value, pointer: &[String]) -> Vec<PropertyInfo> {
    let mut visited = HashSet::new();
    let Some(subschema) = resolve_subschema(root, root, pointer, &mut visited, 0) else {
        return vec![];
    };

    let mut props: Vec<PropertyInfo> = Vec::new();
    let mut seen_names: HashSet<String> = HashSet::new();
    collect_properties_from(root, subschema, &mut props, &mut seen_names, 0);
    props
}

/// Recursively collect properties from a schema, merging composition branches.
fn collect_properties_from(
    root: &serde_json::Value,
    schema: &serde_json::Value,
    props: &mut Vec<PropertyInfo>,
    seen: &mut HashSet<String>,
    depth: usize,
) {
    collect_properties_branch(root, schema, props, seen, depth, true);
}

/// Internal recursive helper for collecting properties.
///
/// `use_required` controls whether the `required` keyword from this schema
/// is applied to the properties it declares. It is `true` for the top-level
/// schema and `allOf` branches (all branches must apply), and `false` for
/// `anyOf`/`oneOf`/`then`/`else` branches (only one branch applies).
fn collect_properties_branch(
    root: &serde_json::Value,
    schema: &serde_json::Value,
    props: &mut Vec<PropertyInfo>,
    seen: &mut HashSet<String>,
    depth: usize,
    use_required: bool,
) {
    if depth > MAX_SCHEMA_DEPTH {
        return;
    }

    // Follow $ref.
    let mut visited = HashSet::new();
    let Some(schema) = follow_ref(root, schema, &mut visited) else {
        return;
    };

    // Collect required set for this schema.
    let required: HashSet<&str> = if use_required {
        schema
            .get("required")
            .and_then(|v| v.as_array())
            .map(|arr| arr.iter().filter_map(|v| v.as_str()).collect())
            .unwrap_or_default()
    } else {
        HashSet::new()
    };

    // Collect properties.
    if let Some(properties) = schema.get("properties").and_then(|v| v.as_object()) {
        for (name, prop_schema) in properties {
            if !seen.insert(name.clone()) {
                continue; // Already seen from an earlier branch.
            }

            // Follow $ref on the property schema for metadata.
            let mut prop_visited = HashSet::new();
            let resolved_prop =
                follow_ref(root, prop_schema, &mut prop_visited).unwrap_or(prop_schema);

            let description = format_annotation(resolved_prop);
            let schema_type = schema_type_string(resolved_prop);

            props.push(PropertyInfo {
                name: name.clone(),
                required: required.contains(name.as_str()),
                description,
                schema_type,
            });
        }
    }

    // Recurse into allOf branches (required is inherited).
    if let Some(all_of) = schema.get("allOf").and_then(|v| v.as_array()) {
        for branch in all_of {
            collect_properties_branch(root, branch, props, seen, depth + 1, true);
        }
    }

    // Recurse into anyOf/oneOf branches (required is not inherited).
    for key in ["anyOf", "oneOf"] {
        if let Some(branches) = schema.get(key).and_then(|v| v.as_array()) {
            for branch in branches {
                collect_properties_branch(root, branch, props, seen, depth + 1, false);
            }
        }
    }

    // Recurse into conditional subschemas (required is not inherited).
    if let Some(then) = schema.get("then") {
        collect_properties_branch(root, then, props, seen, depth + 1, false);
    }
    if let Some(else_) = schema.get("else") {
        collect_properties_branch(root, else_, props, seen, depth + 1, false);
    }
}

/// Extract a display type string from a schema `type` keyword.
///
/// Handles single types and type arrays (e.g. `["string", "null"]`),
/// returning `None` for the unconstrained `null` type.
fn schema_type_string(schema: &serde_json::Value) -> Option<String> {
    match schema.get("type")? {
        serde_json::Value::String(s) => {
            if s == "null" {
                None
            } else {
                Some(s.clone())
            }
        }
        serde_json::Value::Array(arr) => {
            let types: Vec<String> = arr
                .iter()
                .filter_map(|v| v.as_str())
                .filter(|t| *t != "null")
                .map(|s| s.to_string())
                .collect();
            if types.is_empty() {
                None
            } else {
                Some(types.join(" | "))
            }
        }
        _ => None,
    }
}

/// Format title and description from a schema node into a single string.
fn format_annotation(schema: &serde_json::Value) -> Option<String> {
    let title = schema.get("title").and_then(|v| v.as_str());
    let description = schema.get("description").and_then(|v| v.as_str());
    match (title, description) {
        (Some(t), Some(d)) => Some(format!("{t}: {d}")),
        (Some(t), None) => Some(t.to_string()),
        (None, Some(d)) => Some(d.to_string()),
        (None, None) => None,
    }
}

/// Collect possible value suggestions for a property at the given pointer path.
///
/// Navigates to the subschema at `pointer` + `property_name`, then inspects
/// `enum`, `const`, `type`, and composition keywords to generate value
/// suggestions. Results are deduplicated so overlapping branches do not
/// produce duplicate completion items.
pub fn collect_values(
    root: &serde_json::Value,
    pointer: &[String],
    property_name: &str,
) -> Vec<ValueSuggestion> {
    let mut full_pointer: Vec<String> = pointer.to_vec();
    full_pointer.push(property_name.to_string());

    let Some(subschema) = resolve_subschema_at_pointer(root, &full_pointer) else {
        return vec![];
    };

    let mut suggestions = Vec::new();
    let mut seen = HashSet::new();
    collect_values_from(root, subschema, &mut suggestions, &mut seen, 0);
    suggestions
}

/// Recursively collect value suggestions from a schema and its composition
/// branches, deduplicating by value.
fn collect_values_from(
    root: &serde_json::Value,
    schema: &serde_json::Value,
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<ValueSuggestionKey>,
    depth: usize,
) {
    if depth > MAX_SCHEMA_DEPTH {
        return;
    }

    // Follow $ref.
    let mut visited = HashSet::new();
    let Some(schema) = follow_ref(root, schema, &mut visited) else {
        return;
    };

    // Check for const (a single fixed value).
    if let Some(const_val) = schema.get("const") {
        let suggestion = ValueSuggestion::Const(const_val.clone());
        if seen.insert(value_suggestion_key(&suggestion)) {
            suggestions.push(suggestion);
        }
        return;
    }

    // Check for enum (a list of allowed values).
    if let Some(enum_vals) = schema.get("enum").and_then(|v| v.as_array()) {
        for val in enum_vals {
            let suggestion = ValueSuggestion::Enum(val.clone());
            if seen.insert(value_suggestion_key(&suggestion)) {
                suggestions.push(suggestion);
            }
        }
        return;
    }

    // Check for type-based suggestions.
    if let Some(type_value) = schema.get("type") {
        collect_type_value_suggestions(type_value, suggestions, seen);
    }

    // OpenAPI-style `nullable: true` adds null as a valid value.
    if schema.get("nullable").and_then(|v| v.as_bool()) == Some(true) {
        let suggestion = ValueSuggestion::Null;
        if seen.insert(value_suggestion_key(&suggestion)) {
            suggestions.push(suggestion);
        }
    }

    // Recurse into composition branches.
    for key in ["allOf", "anyOf", "oneOf"] {
        if let Some(branches) = schema.get(key).and_then(|v| v.as_array()) {
            for branch in branches {
                collect_values_from(root, branch, suggestions, seen, depth + 1);
            }
        }
    }

    // Conditional subschemas.
    if let Some(then) = schema.get("then") {
        collect_values_from(root, then, suggestions, seen, depth + 1);
    }
    if let Some(else_) = schema.get("else") {
        collect_values_from(root, else_, suggestions, seen, depth + 1);
    }
}

/// Convert a JSON Schema `type` value into value suggestions.
fn collect_type_value_suggestions(
    type_value: &serde_json::Value,
    suggestions: &mut Vec<ValueSuggestion>,
    seen: &mut HashSet<ValueSuggestionKey>,
) {
    let add = |suggestions: &mut Vec<ValueSuggestion>,
               seen: &mut HashSet<ValueSuggestionKey>,
               suggestion: ValueSuggestion| {
        if seen.insert(value_suggestion_key(&suggestion)) {
            suggestions.push(suggestion);
        }
    };

    match type_value {
        serde_json::Value::String(s) => match s.as_str() {
            "boolean" => add(suggestions, seen, ValueSuggestion::Boolean),
            "null" => add(suggestions, seen, ValueSuggestion::Null),
            _ => {}
        },
        serde_json::Value::Array(arr) => {
            for t in arr {
                if let Some(s) = t.as_str() {
                    match s {
                        "boolean" => add(suggestions, seen, ValueSuggestion::Boolean),
                        "null" => add(suggestions, seen, ValueSuggestion::Null),
                        _ => {}
                    }
                }
            }
        }
        _ => {}
    }
}

/// Resolve the subschema at a given JSON pointer path within a schema.
fn resolve_subschema<'a>(
    root: &'a serde_json::Value,
    schema: &'a serde_json::Value,
    pointer: &[String],
    visited: &mut HashSet<String>,
    depth: usize,
) -> Option<&'a serde_json::Value> {
    if depth > MAX_SCHEMA_DEPTH {
        return None;
    }

    // Follow $ref before descending.
    let schema = follow_ref(root, schema, visited)?;

    if pointer.is_empty() {
        return Some(schema);
    }

    let segment = &pointer[0];
    let rest = &pointer[1..];

    // Try properties.<segment>
    if let Some(prop_schema) = schema
        .get("properties")
        .and_then(|p| p.get(segment.as_str()))
    {
        return resolve_subschema(root, prop_schema, rest, visited, depth + 1);
    }

    // Try allOf branches.
    if let Some(all_of) = schema.get("allOf").and_then(|v| v.as_array()) {
        for branch in all_of {
            if let Some(result) = resolve_subschema(root, branch, pointer, visited, depth + 1) {
                return Some(result);
            }
        }
    }

    // Try items (for array elements with numeric index).
    if let Ok(idx) = segment.parse::<usize>() {
        if let Some(items) = schema.get("items")
            && (items.is_object() || items.is_boolean())
        {
            return resolve_subschema(root, items, rest, visited, depth + 1);
        }
        // Try prefixItems[i]
        if let Some(prefix_items) = schema.get("prefixItems").and_then(|p| p.as_array())
            && let Some(item_schema) = prefix_items.get(idx)
        {
            return resolve_subschema(root, item_schema, rest, visited, depth + 1);
        }
    }

    None
}

/// Follow `$ref` within the same document. Only fragment references (`#/...`)
/// are followed. Returns the resolved schema, or the input schema if no `$ref`.
fn follow_ref<'a>(
    root: &'a serde_json::Value,
    schema: &'a serde_json::Value,
    visited: &mut HashSet<String>,
) -> Option<&'a serde_json::Value> {
    let ref_str = match schema.get("$ref").and_then(|v| v.as_str()) {
        Some(r) => r,
        None => return Some(schema),
    };

    // Only follow fragment references within the same document.
    if !ref_str.starts_with('#') {
        return Some(schema);
    }

    // Cycle detection.
    if !visited.insert(ref_str.to_string()) {
        return None;
    }

    // Parse the JSON Pointer from the fragment (strip leading `#/`).
    let pointer_str = ref_str.strip_prefix("#/").unwrap_or("");
    if pointer_str.is_empty() {
        return Some(root);
    }

    let mut target = root;
    for segment in pointer_str.split('/') {
        // Unescape JSON Pointer encoding (~1 = /, ~0 = ~).
        let unescaped = segment.replace("~1", "/").replace("~0", "~");
        target = target.get(&unescaped)?;
    }

    // Recursively follow if the target itself has a $ref.
    follow_ref(root, target, visited)
}

