+    fn collect_values_nullable_array_type() {
+        let schema = serde_json::json!({
+            "properties": {
+                "nickname": { "type": ["string", "null"] }
+            }
+        });
+        let values = collect_values(&schema, &[], "nickname");
+        assert_eq!(values.len(), 1);
+        assert!(matches!(&values[0], ValueSuggestion::Null));
+    }
+
+    #[test]
+    fn collect_values_nullable_openapi() {
+        let schema = serde_json::json!({
+            "properties": {
+                "count": { "type": "integer", "nullable": true }
+            }
+        });
+        let values = collect_values(&schema, &[], "count");
+        assert_eq!(values.len(), 1);
+        assert!(matches!(&values[0], ValueSuggestion::Null));
+    }
+
+    #[test]
+    fn collect_values_anyof_with_null() {
+        let schema = serde_json::json!({
+            "properties": {
+                "enabled": {
+                    "anyOf": [
+                        { "type": "boolean" },
+                        { "type": "null" }
+                    ]
+                }
+            }
+        });
+        let values = collect_values(&schema, &[], "enabled");
+        assert_eq!(values.len(), 2);
+        assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Boolean)));
+        assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Null)));
+    }
+
+    #[test]
+    fn collect_values_anyof_enum_and_boolean() {
+        let schema = serde_json::json!({
+            "properties": {
+                "mode": {
+                    "anyOf": [
+                        { "enum": ["dark", "light"] },
+                        { "type": "boolean" }
+                    ]
+                }
+            }
+        });
+        let values = collect_values(&schema, &[], "mode");
+        // Boolean is a single suggestion that expands to true/false completion items.
+        assert_eq!(values.len(), 3);
+        assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Enum(v) if v == "dark")));
+        assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Enum(v) if v == "light")));
+        assert!(values.iter().any(|v| matches!(v, ValueSuggestion::Boolean)));
+    }
+
+    #[test]
+    fn collect_values_no_duplicates_across_branches() {
+        let schema = serde_json::json!({
+            "properties": {
+                "mode": {
+                    "anyOf": [
+                        { "enum": ["dark", "light"] },
+                        { "enum": ["light", "auto"] }
+                    ]
+                }
+            }
+        });
+        let values = collect_values(&schema, &[], "mode");
+        assert_eq!(values.len(), 3);
+        let labels: Vec<String> = values
+            .iter()
+            .map(|v| match v {
+                ValueSuggestion::Enum(v) => v.as_str().unwrap().to_string(),
+                _ => panic!("unexpected suggestion"),
+            })
+            .collect();
+        assert!(labels.contains(&"dark".to_string()));
+        assert!(labels.contains(&"light".to_string()));
+        assert!(labels.contains(&"auto".to_string()));
+    }
 }
